  ('optometrist-moex-02268', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '利用雙眼角膜反射光點位置來評估斜視，由於視軸（visual axis）與瞳孔軸（pupillary axis）並非一致，造 成反射光點位置通常會稍微偏向鼻側，而非位在瞳孔中心，此一由視軸與瞳孔軸相交所形成的夾角稱為：', '["κ角", "λ角", "α角", "γ角"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
